mapper.select:
SELECT o.*,
       r_sweet.ref_value as sweetness_name,
       r_ice.ref_value as ice_level_name
FROM `order` o
LEFT JOIN reference r_sweet ON r_sweet.ref_type = 'sweetness' AND r_sweet.ref_code = o.sweetness
LEFT JOIN reference r_ice ON r_ice.ref_type = 'ice_level' AND r_ice.ref_code = o.ice_level

    o.user_id = #{userId}

        AND o.product_name LIKE CONCAT('%', #{productName}, '%')


        AND o.sweetness = #{sweetness}


        AND o.ice_level = #{iceLevel}


        AND o.created_at >= #{startTime}


        AND o.created_at <= #{endTime}


ORDER BY o.created_at DESC

mapper.update:
UPDATE `order`
user_id = #{userId}, product_id = #{productId}, product_name = #{productName}, sweetness = #{sweetness}, ice_level = #{iceLevel}, quantity = #{quantity}, unit_price = #{unitPrice}, total_price = #{totalPrice}, remark = #{remark}, updated_at = NOW()
WHERE id = #{id}
